(function(){"use strict";const P=window.OrbArena.PowerRegistry,R=(id,name,description,cooldown,duration,powerBudget,tags,activate,extra={})=>P.register({id,name,category:tags.includes("veneno")?"veneno":"clones",type:"active",rarity:"Épica",description,cooldown,duration,powerBudget,tags,icon:"◉",activate,...extra});
R("corrosive_bloom","Corrosive Bloom","Flor tóxica móvel que explode em veneno.",8,6,14,["veneno","invocação"],({world,actor,target,context})=>context.summon(world,actor,{kind:"corrosive-bloom",behavior:"stationary",life:6,health:26,explodeOnDeath:13,healAura:1.5,scale:.5}),{onEvent:({world,actor,target,event,context})=>{if(event.type==="damage"&&target&&event.damage>15)context.poison(target,actor,1,4,1.6);}});
R("living_mine","Living Mine","Mina viva persegue lentamente o alvo.",7,7,13,["mina","invocação"],({world,actor,context})=>context.summon(world,actor,{kind:"living-mine",behavior:"chase",life:7,health:18,damage:4,explodeOnDeath:18,speed:180,scale:.42}));
R("poison_clone","Poison Clone","Clone que deixa uma poça tóxica ao expirar.",10,6,16,["clone","veneno"],({world,actor,context})=>context.clone(world,actor,{kind:"poison-clone",life:6,damageRatio:.32,explosion:16,color:"#74e66b"}),{onEvent:({world,actor,target,event,context})=>{if(event.type==="damage"&&target)context.poison(target,actor,1,4,1.5);}});
R("mirror_dash","Mirror Dash","Executa dash e envia uma imagem na direção contrária.",7,3,12,["clone","dash"],({world,actor,target,context})=>{context.impulse(actor,target.x-actor.x,target.y-actor.y,250);context.clone(world,actor,{kind:"mirror-dash-clone",life:2.5,damageRatio:.25,behavior:"chase"});});
R("soul_link","Soul Link","Divide dano com a réplica vinculada.",11,7,16,["clone","defesa"],({world,actor,context})=>{const clone=context.clone(world,actor,{kind:"soul-link-clone",life:8,healthRatio:.35,damageRatio:.3});actor.characterState.data.soulLink=clone;},{onReceive:({actor,event})=>{const clone=actor.characterState.data.soulLink;if(clone?.active&&event.damage){const share=Math.min(clone.health,event.damage*.28);clone.health-=share;actor.heal(share*.45);}}});
R("spore_cloud","Spore Cloud","Nuvem aplica veneno progressivo.",9,8,15,["veneno","área"],({world,actor,target,context})=>context.zone(world,actor,target,{kind:"poison",radius:135,life:8,power:2.2,color:"#78d85a",data:{interval:.6}}));
R("orbit_swap","Orbit Swap","Troca posição com um clone ou satélite.",7,1,12,["clone","teleporte"],({world,actor,target,context})=>{const s=world.summons.find(x=>x.active&&x.owner===actor);if(s){const x=actor.x,y=actor.y;context.teleport(world,actor,s.x,s.y);s.x=x;s.y=y;}else context.teleport(world,actor,target.x-70,target.y);});
R("toxic_reflection","Toxic Reflection","Reflete parte do veneno recebido.",10,6,13,["veneno","reativo"],({actor})=>actor.characterState.data.toxicReflection=6,{onReceive:({actor,target,context})=>{if(actor.poison?.stacks&&target&&actor.characterState.data.toxicReflection>0)context.poison(target,actor,Math.ceil(actor.poison.stacks*.35),4,1.4);}});
R("clone_sacrifice","Clone Sacrifice","Consome a réplica mais antiga para sustentar o criador.",8,1,13,["clone","cura","escudo"],({world,actor,context})=>{const clone=world.summons.find(x=>x.active&&x.owner===actor&&x.kind.includes("clone"));if(clone){clone.life=0;context.heal(actor,22);context.shield(actor,26);}else context.clone(world,actor,{life:4,damageRatio:.25});});
R("projectile_harvest","Projectile Harvest","Converter disparos destruídos em energia e escudo.",9,5,14,["defesa","projétil"],({actor,context})=>{const removed=context.removeProjectiles(actor,145);context.shield(actor,removed*7);actor.characterState.ultimateCharge=Math.min(100,actor.characterState.ultimateCharge+removed*8);});
}());
